Here is a clean reimplementation from scratch. The obfuscated code is doing an A* search on a randomly generated 2D grid with 8-direction movement, configurable heuristic (`manhattan` or Euclidean), diagonal move cost `1.414`, straight move cost `1`, and a maximum iteration cap.

```javascript
const gridWidth = 20;
const gridHeight = 15;

const config = {
  heuristic: "manhattan",   // "manhattan" or "euclidean"
  diagonalCost: 1.414,
  straightCost: 1,
  maxIterations: 1000,
  obstacleChance: 0.25
};

function createRandomGrid(width, height, obstacleChance) {
  const grid = [];

  for (let y = 0; y < height; y++) {
    const row = [];
    for (let x = 0; x < width; x++) {
      row.push(Math.random() < obstacleChance ? 1 : 0);
    }
    grid.push(row);
  }

  return grid;
}

function heuristicDistance(a, b, heuristicType) {
  const dx = Math.abs(a.x - b.x);
  const dy = Math.abs(a.y - b.y);

  if (heuristicType === "manhattan") {
    return dx + dy;
  }

  return Math.sqrt(dx * dx + dy * dy);
}

function toKey(node) {
  return `${node.x},${node.y}`;
}

function parseKey(key) {
  const [x, y] = key.split(",").map(Number);
  return { x, y };
}

function getNeighbors(node, grid, config) {
  const directions = [
    { dx: 0,  dy: -1, cost: config.straightCost },
    { dx: 0,  dy: 1,  cost: config.straightCost },
    { dx: -1, dy: 0,  cost: config.straightCost },
    { dx: 1,  dy: 0,  cost: config.straightCost },
    { dx: -1, dy: -1, cost: config.diagonalCost },
    { dx: 1,  dy: -1, cost: config.diagonalCost },
    { dx: -1, dy: 1,  cost: config.diagonalCost },
    { dx: 1,  dy: 1,  cost: config.diagonalCost }
  ];

  const neighbors = [];

  for (const dir of directions) {
    const x = node.x + dir.dx;
    const y = node.y + dir.dy;

    const inBounds =
      x >= 0 &&
      x < grid[0].length &&
      y >= 0 &&
      y < grid.length;

    if (!inBounds) continue;
    if (grid[y][x] !== 0) continue;

    neighbors.push({ x, y, moveCost: dir.cost });
  }

  return neighbors;
}

function reconstructPath(cameFrom, currentKey, openSet, closedSet) {
  const path = [];

  while (currentKey) {
    const node =
      openSet[currentKey] ||
      closedSet[currentKey] ||
      parseKey(currentKey);

    path.push({ x: node.x, y: node.y });
    currentKey = cameFrom[currentKey];
  }

  return path;
}

function findRoute(start, goal, grid, config) {
  const openSet = {};
  const closedSet = {};
  const cameFrom = {};
  const gScore = {};
  const fScore = {};

  const startKey = toKey(start);
  let iterations = 0;

  openSet[startKey] = { ...start };
  gScore[startKey] = 0;
  fScore[startKey] = heuristicDistance(start, goal, config.heuristic);

  while (Object.keys(openSet).length > 0 && iterations < config.maxIterations) {
    iterations++;

    let currentKey = null;
    let bestScore = Infinity;

    for (const key in openSet) {
      if (fScore[key] < bestScore) {
        bestScore = fScore[key];
        currentKey = key;
      }
    }

    const current = openSet[currentKey];

    if (current.x === goal.x && current.y === goal.y) {
      return {
        path: reconstructPath(cameFrom, currentKey, openSet, closedSet),
        cost: gScore[currentKey],
        iterations
      };
    }

    delete openSet[currentKey];
    closedSet[currentKey] = current;

    const neighbors = getNeighbors(current, grid, config);

    for (const neighbor of neighbors) {
      const neighborKey = toKey(neighbor);

      if (closedSet[neighborKey]) {
        continue;
      }

      const tentativeG = gScore[currentKey] + neighbor.moveCost;

      if (gScore[neighborKey] === undefined || tentativeG < gScore[neighborKey]) {
        cameFrom[neighborKey] = currentKey;
        gScore[neighborKey] = tentativeG;
        fScore[neighborKey] =
          tentativeG + heuristicDistance(neighbor, goal, config.heuristic);

        openSet[neighborKey] = { x: neighbor.x, y: neighbor.y };
      }
    }
  }

  return {
    path: [],
    cost: Infinity,
    iterations
  };
}

// Example usage
const grid = createRandomGrid(gridWidth, gridHeight, config.obstacleChance);

const start = { x: 0, y: 0 };
const goal = { x: gridWidth - 1, y: gridHeight - 1 };

// Ensure endpoints are walkable
grid[start.y][start.x] = 0;
grid[goal.y][goal.x] = 0;

const result = findRoute(start, goal, grid, config);

console.log(
  "Path length:",
  result.path.length,
  "Cost:",
  result.cost,
  "Iterations:",
  result.iterations
);
```

### What the original code does
- Builds a `20 x 15` grid.
- Randomly places obstacles with probability `0.25`.
- Ensures start `(0,0)` and goal `(width-1,height-1)` are open.
- Uses **A\*** pathfinding.
- Allows movement in 8 directions.
- Uses:
  - cost `1` for orthogonal moves
  - cost `1.414` for diagonal moves
- Uses either:
  - Manhattan heuristic, or
  - Euclidean heuristic
- Stops after `1000` iterations if no route is found.

